Hi @bbBowser!

Currently, the build widget only works when targeting non-table elements:

```html
<div id="myTable2">
  <table>...</table>
</div>
```

So to bind to events, you'll need to target the table inside the div ([demo](https://jsfiddle.net/Mottie/gzysy10p/2/)); internally, all triggered events use jQuery's [`triggerHandler`](http://api.jquery.com/triggerHandler/) function which doesn't allow for event propagation because it would be troublesome to have events like `sortStart` bubble up from a nested table.

```js
$('#table')
  .tablesorter({
    theme: 'blue',
    widgets: ['zebra'],
    data : dataObject
  })
  .find('table')
  .on('sortStart', function(){
    alert('ok');
  });
```

Fixed per our discussion in IRC using the following code:

```js
pager_ajaxProcessing: function (result, table, xhr) {
  if (result) {
    result.rows = $(result.rows);
    var pager = table.config.pager,
      rows = result.rows.length;
    // set the filteredRows to the current page * size setting,
    // add one so the next page is still available
    result.filteredRows = pager.size * (pager.page + 1) + 1;
    if (rows < pager.size) {
      // adjust filteredRows size to prevent paging to the next empty page
      result.filteredRows += rows - pager.size;
    }
    // ...
    return result
  }
},
```

