import six

from django.contrib.sites.models import Site
from django.conf import settings

from social.apps.django_app.default.models import DjangoUserMixin as SocialAUth_DjangoUserMixin, DjangoStorage as SocialAuth_DjangoStorage


class SocialAuthUserMixinOverride(SocialAUth_DjangoUserMixin):
    """
    Override social auth storage class' user methods to be site specific
    """

    @classmethod
    def user_exists(cls, *args, **kwargs):
        # filter by site_id
        kwargs.update({'site': Site.objects.get(pk=settings.SITE_ID)})
        super(SocialAuthUserMixinOverride).user_exists(cls, *args, **kwargs)

    @classmethod
