@jonashaag for Werkzeug:
```python
_client = None


def get_client():
    global _client
    if _client is not None:
        return _client

    import settings

    config = settings.RAVEN_CONFIG.copy()
    release = get_git_tag()
    if release:
        config['release'] = release

    _client = Client(**config)
    return _client

class Client(raven.Client):
    # used raven.contrib.django.client as an example

    def get_user_info(self, user):
        user_info = {
            'email': user.email,
        }
        return user_info

    def get_data_from_request(self, request):
        data = {}
        if request.user:
            data['user'] = self.get_user_info(request.user)
        body = request.get_data() if request.method != 'GET' else None
        data.update({
            'request': {
                'method': request.method,
                'url': get_current_url(request.environ),
                'query_string': request.query_string,
                'data': body,
                'cookies': request.cookies,
                'headers': dict(get_headers(request.environ)),
                'env': dict(get_environ(request.environ)),
            }
        })
        return data

    def capture(self, event_type, **kwargs):
        request = self.get_request()
        if request is not None:
            data = kwargs.setdefault('data', {})
            data.update(self.get_data_from_request(request))
        return super().capture(event_type, **kwargs)

    @cached_property
    def get_request(self):
        from brain.utils.request import get_request
        return get_request
```

